ALL_SEGMENTS = {11: TRAJ11, 12: TRAJ12, 13: TRAJ13, 14: TRAJ14,
                21: TRAJ21, 22: TRAJ22, 23: TRAJ23}


def main():
    obs = {}
    with open(DATA_DIR / "cmm_input_points.csv", newline="") as f:
        seq_counters = defaultdict(int)
        for row in csv.DictReader(f, delimiter=";"):
            tid = int(row["id"])
            seq = seq_counters[tid]
            seq_counters[tid] += 1
            obs[(tid, seq)] = {"ts": row["timestamp"], "x": row["x"], "y": row["y"]}

    all_rows = []
    for tid, segments in sorted(ALL_SEGMENTS.items()):
        if not segments:
            continue
        max_seq = max(end for _, _, end in segments)
        point_edges = [None] * (max_seq + 1)
        for edge_id, start, end in segments:
            for seq in range(start, end + 1):
                point_edges[seq] = str(edge_id)  # -1, 0, or positive edge id

        total = unmatched = 0
        unique_edges = set()
        for seq in range(len(point_edges)):
            if (tid, seq) not in obs or point_edges[seq] is None:
                continue
            eid = point_edges[seq]
            o = obs[(tid, seq)]
            all_rows.append({"id": str(tid), "seq": str(seq), "timestamp": o["ts"],
                             "x": o["x"], "y": o["y"], "edge_id": eid})
            total += 1
            if eid in ("0", "-1"):
                unmatched += 1
            else:
                unique_edges.add(eid)

        spp = sum(1 for k in obs if k[0] == tid)
        nf = unmatched
        print(f"Traj {tid}: {total} GT epochs ({nf} excluded, {len(unique_edges)} edges), SPP: {spp}")

    out = DATA_DIR / "ground_truth.csv"
    with open(out, "w", newline="") as f:
        w = csv.DictWriter(f, fieldnames=["id","seq","timestamp","x","y","edge_id"], delimiter=";")
        w.writeheader(); w.writerows(all_rows)
    print(f"\nSaved: {out} ({len(all_rows)} rows)")


if __name__ == "__main__":
    main()
